<?php
namespace App\Http\Controllers\Api;
use App\Enums\AccountType;use App\Http\Controllers\Controller;use App\Models\LedgerAccount;use App\Support\Tenancy\TenantContext;use Illuminate\Http\JsonResponse;use Illuminate\Http\Request;use Illuminate\Validation\Rule;
class LedgerAccountController extends Controller{public function index():JsonResponse{return response()->json(LedgerAccount::query()->with('parent')->orderBy('code')->get());}public function store(Request $request):JsonResponse{return response()->json(LedgerAccount::query()->create($this->validated($request)),201);}public function show(LedgerAccount $ledgerAccount):JsonResponse{return response()->json($ledgerAccount->load('children'));}public function update(Request $request,LedgerAccount $ledgerAccount):JsonResponse{$ledgerAccount->update($this->validated($request,$ledgerAccount));return response()->json($ledgerAccount->refresh());}public function destroy(LedgerAccount $ledgerAccount):mixed{abort_if($ledgerAccount->is_system||$ledgerAccount->lines()->exists()||$ledgerAccount->children()->exists(),422,'This account cannot be deleted.');$ledgerAccount->delete();return response()->noContent();}private function validated(Request $request,?LedgerAccount $account=null):array{$tenant=app(TenantContext::class)->id();return $request->validate(['parent_id'=>['nullable','ulid',Rule::exists('ledger_accounts','id')->where('cooperative_id',$tenant)],'code'=>['required','string','max:30',Rule::unique('ledger_accounts')->where('cooperative_id',$tenant)->ignore($account)],'name'=>['required','string','max:160'],'type'=>['required',Rule::enum(AccountType::class)],'normal_balance'=>['required','in:debit,credit'],'is_control_account'=>['required','boolean'],'allows_direct_posting'=>['required','boolean'],'is_active'=>['required','boolean'],'description'=>['nullable','string','max:2000']]);}}
